import { jsx } from 'react/jsx-runtime';
import { useMemo } from 'react';
import { classNames } from '../../../helpers/classnames.js';
import { Typography } from '../../Typography/Typography.js';
import { formatNumber } from '../utils.js';

const BadgeContent = ({ count, error = false, warning = false, hideBadgeContent = false, size = 'small', stanalone, }) => {
    const badgeContent = useMemo(() => formatNumber(count), [count]);
    return (jsx(Typography, { "data-testid": "BadgeContent", className: classNames('dsb_badge', `dsb_badge--${size}`, {
            'dsb_badge--error': error,
            'dsb_badge--exclamation': warning,
            'dsb_badge--standalone': stanalone,
        }), variant: "overline", children: !hideBadgeContent && (warning ? '!' : badgeContent) }));
};

export { BadgeContent };
